window.CA = {"date": "Wednesday, 01 July 2026", "updated": "2026-07-01 15:21", "updated_label": "01 Jul 2026, 15:21 IST", "items": [{"title": "General Dhiraj Seth Takes Charge as 31st Chief of Army Staff with 'VIJAY' Vision", "category": "persons", "category_name": "Persons & Awards in News", "summary": "General Dhiraj Seth assumed charge as the 31st Chief of Army Staff (COAS) of the Indian Army on July 1, 2026. He succeeds the previous Army Chief and has outlined a 'VIJAY' vision for the force. Seth is a senior officer who will oversee India's military modernisation and operational readiness. His appointment comes at a strategically sensitive time given ongoing tensions in the neighbourhood.", "exam_angle": "Appointments of service chiefs are standard 'Persons in News' items for UPSC. The Army Chief is the principal staff officer to the government and head of the Indian Army under the supreme command of the President.", "gs_paper": "GS Paper 3 (Defence)", "key_facts": ["General Dhiraj Seth: 31st Chief of Army Staff of India", "Assumed charge: July 1, 2026", "Vision framework named: 'VIJAY'", "Army Chief is appointed by the President of India on advice of the government"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "India and Japan Explore Yen-Rupee Direct Trade Settlement to Reduce Dollar Dependence", "category": "ir", "category_name": "International Relations", "summary": "India and Japan are exploring a direct yen-rupee trade settlement mechanism that would reduce reliance on the US dollar in bilateral trade payments. Japanese PM Sanae Takaichi arrived in New Delhi for her first visit, with Indo-Pacific cooperation as a key agenda item. The two sides are expected to discuss deepening economic ties, including currency settlement frameworks. This follows India's similar arrangements with other countries to internationalise the rupee.", "exam_angle": "Relevant to India's push for rupee internationalisation and de-dollarisation of trade. Also connects to India-Japan bilateral relations, the Indo-Pacific framework, and RBI's policy on alternate settlement mechanisms.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Proposed mechanism: Direct yen-rupee trade settlement", "Objective: Reduce dependence on US dollar in bilateral trade", "Japanese PM Sanae Takaichi visited New Delhi (first visit as PM)", "Connects to India's broader rupee internationalisation policy"], "source": "Moneycontrol.com", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Pakistan Deputy PM Asserts Indus Waters Treaty 'Valid and Binding'; Afghanistan Strikes ISIS in Balochistan", "category": "ir", "category_name": "International Relations", "summary": "Pakistan's Deputy PM stated that the Indus Waters Treaty (IWT) remains 'valid, binding and operative', amid India's move to put the treaty in abeyance following the Pahalgam attack. Separately, Afghanistan launched airstrikes on ISIS targets in Pakistan's Balochistan region, days after Pakistan conducted its own airstrikes on Afghan territory. India strongly condemned Pakistan's earlier airstrikes on Afghanistan through the MEA. Russia urged both countries to resolve disputes through diplomacy.", "exam_angle": "The IWT (1960) is a key treaty for GS Paper 2 IR and GS Paper 3 (water security). The Afghanistan-Pakistan tensions are directly relevant to India's neighbourhood policy and regional security questions.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Indus Waters Treaty signed: 1960, brokered by World Bank", "India put IWT in abeyance after the Pahalgam terror attack", "Pakistan's Deputy PM declared IWT 'valid, binding and operative'", "India's MEA strongly condemned Pakistan's airstrikes on Afghan territory"], "source": "The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Commercial LPG Cylinder Price Cut by Rs 183.50 from July 1; Centre Lifts Fuel Sales Restrictions", "category": "economy", "category_name": "Economy & Banking", "summary": "The Centre reduced commercial LPG cylinder prices by Rs 183.50 effective July 1, 2026, providing relief to businesses such as hotels and restaurants, though domestic household cylinder prices remained unchanged. Separately, the government lifted restrictions on the open-market sale of petrol and diesel from July 1 amid easing global crude supply. The price cut follows a moderation in global LPG prices. Nayara Energy also reduced petrol and diesel prices at its retail outlets.", "exam_angle": "LPG pricing policy, government's role in fuel price regulation, and the administered vs market-linked pricing debate are important for GS Paper 3 Economy. Also relevant to inflation management and subsidy policy.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Commercial LPG price cut: Rs 183.50 per cylinder from July 1, 2026", "Domestic LPG prices: unchanged", "Centre lifted restrictions on open-market sale of petrol and diesel from July 1", "Price revision linked to moderation in global crude/LPG prices"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "US Supreme Court Delivers Blow to Trump's Birthright Citizenship Bid; Relief for Indians", "category": "ir", "category_name": "International Relations", "summary": "The US Supreme Court ruled against Donald Trump's executive order seeking to end birthright citizenship, upholding the 14th Amendment's guarantee of citizenship to all persons born on US soil. The ruling is seen as significant for Indians—one of the largest groups in the US immigration queue—as it preserves citizenship rights for children of immigrants, including those on H-1B visas. Trump responded critically, making a jab at China. The ruling was hailed as a major check on executive overreach.", "exam_angle": "Relevant to understanding US constitutional law (14th Amendment), India-US relations through the Indian diaspora lens, and the ongoing US immigration policy debate which affects Indian IT professionals and students.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["US Supreme Court struck down Trump's executive order on birthright citizenship", "Constitutional basis: 14th Amendment to US Constitution", "Ruling is significant for Indians—largest group in US immigration backlog", "Trump's order had sought to end automatic citizenship for children of non-citizens/undocumented immigrants"], "source": "The Times of India", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Foreign Buying of Indian Government Bonds Hits Record High Following Tax Concessions", "category": "economy", "category_name": "Economy & Banking", "summary": "Foreign investment in Indian government bonds reached a record high following tax breaks extended to offshore investors. India's inclusion in global bond indices (JP Morgan, Bloomberg) has been a key driver of sustained foreign portfolio inflows into the debt market. The surge reflects growing confidence in India's macroeconomic fundamentals and the attractiveness of Indian sovereign debt at current yields. This also contributed to an improvement in India's external financial position in FY2025-26.", "exam_angle": "Connects to India's bond market reforms, index inclusion, rupee internationalisation, capital account management, and external sector strength—all key GS Paper 3 Economy topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Foreign buying of Indian bonds hit a record high in 2026", "Key trigger: Tax breaks for foreign/offshore investors in Indian government bonds", "India included in JP Morgan and Bloomberg global bond indices", "India's external financial position improved in FY2025-26 (Business Standard)"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Kotak Mahindra Bank to Acquire Deutsche Bank's India Retail, Private Banking and Wealth Business", "category": "economy", "category_name": "Economy & Banking", "summary": "Kotak Mahindra Bank announced an agreement to acquire Deutsche Bank's retail banking, private banking, and wealth management business in India. Deutsche Bank will exit the Indian retail segment through this transaction. This is a significant consolidation move in India's private banking space, potentially expanding Kotak's high-net-worth customer base and product offerings. The deal is subject to regulatory approvals from RBI and other authorities.", "exam_angle": "Relevant to banking sector consolidation in India, RBI's regulatory oversight of mergers and acquisitions in the financial sector, and the evolving competitive landscape of Indian private banking.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Acquirer: Kotak Mahindra Bank", "Target: Deutsche Bank's retail, private banking and wealth management operations in India", "Deal subject to RBI and regulatory approvals", "Represents consolidation in India's private banking/wealth management sector"], "source": "The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "India's Manufacturing PMI Moderates in June 2026 Amid Weaker Demand", "category": "economy", "category_name": "Economy & Banking", "summary": "India's Manufacturing Purchasing Managers' Index (PMI) for June 2026 showed a moderation in growth compared to previous months, driven by weaker new orders and demand conditions. While the index remained in expansion territory (above 50), the pace of growth slowed. The PMI data is compiled by S&P Global and is a closely watched indicator of industrial health and near-term economic momentum.", "exam_angle": "Manufacturing PMI is a key lead indicator for GS Paper 3 Economy (Indian Economy). Numbers above 50 signal expansion; below 50 signal contraction. Relevant to questions on economic slowdown, industrial output, and the Make in India initiative.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["India Manufacturing PMI for June 2026: moderated, but remained above 50 (expansion zone)", "Cause of moderation: Weaker new orders and demand", "PMI compiled by: S&P Global", "PMI above 50 = expansion; below 50 = contraction"], "source": "The New Indian Express", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "US Lifts Sanctions on Four Indian Companies Linked to Russia-Related Measures", "category": "ir", "category_name": "International Relations", "summary": "The United States removed four Indian companies from its sanctions list that had been designated for allegedly facilitating trade with Russia in violation of export controls or sanctions. This move is seen as part of evolving US-India diplomatic engagement and could signal a recalibration of pressure on India over its continued trade with Russia. The delisting follows diplomatic discussions between the two governments.", "exam_angle": "Relevant to India's strategic autonomy, India-US-Russia trilateral dynamics, and the geopolitics of sanctions—a recurring theme in GS Paper 2 IR. Also connects to India's foreign policy of multi-alignment.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["US removed 4 Indian companies from sanctions list", "Reason for original designation: Alleged facilitation of Russia-linked trade/transactions", "Delisting reflects India-US diplomatic engagement", "Context: India has maintained trade with Russia despite Western sanctions post-Ukraine conflict"], "source": "Hindustan Times", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "CBI Arrests IPS Officer Deepak Gahlawat (Haryana Cadre) in Rs 3 Crore Bribery Case", "category": "polity", "category_name": "Polity & Governance", "summary": "The Central Bureau of Investigation (CBI) arrested IPS officer Deepak Gahlawat of the Haryana cadre in connection with an alleged bribery case involving Rs 3 crore. The arrest underscores the CBI's mandate to investigate corruption cases involving senior government officials. Gahlawat's arrest is a significant action against corruption in the civil services.", "exam_angle": "Relevant to GS Paper 2 (Governance) topics such as accountability of civil servants, the role and jurisdiction of the CBI, and prevention of corruption legislation (Prevention of Corruption Act, 1988).", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Arrested by: CBI (Central Bureau of Investigation)", "Accused: IPS officer Deepak Gahlawat, Haryana cadre", "Alleged bribery amount: Rs 3 crore", "Relevant law: Prevention of Corruption Act, 1988"], "source": "The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Delhi High Court: Politicians Must Tolerate Political Humour; Satirical Criticism Not Necessarily Defamation", "category": "polity", "category_name": "Polity & Governance", "summary": "The Delhi High Court, while dealing with a petition by AAP MP Raghav Chadha, held that politicians must tolerate political humour and that satirical criticism does not necessarily constitute defamation. The court directed the takedown of five specific social media posts but refused to grant broader interim protection to Chadha. The judgment reinforces the balance between free speech (Article 19) and the right to reputation.", "exam_angle": "Directly relevant to Fundamental Rights (Article 19 — Freedom of Speech and Expression) and its reasonable restrictions, the law of defamation, and judicial pronouncements on political satire. A standard GS Paper 2 topic.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Court: Delhi High Court", "Petitioner: Raghav Chadha (AAP MP, Rajya Sabha)", "Ruling: Politicians must tolerate political humour; satire ≠ defamation per se", "Constitutional angle: Article 19(1)(a) — Freedom of Speech; Article 19(2) — Reasonable restrictions"], "source": "The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Madras High Court Upholds Death Penalty in Child Abuse Case, Terms It 'More Heinous Than Murder'", "category": "polity", "category_name": "Polity & Governance", "summary": "The Madras High Court upheld the death penalty awarded to a convict in a child sexual abuse case, describing the crime as 'more heinous than murder'. The court's observations reinforce the application of the 'rarest of rare' doctrine in heinous crimes against children. This ruling is significant in the context of the POCSO Act (Protection of Children from Sexual Offences) and the debate around capital punishment in India.", "exam_angle": "Connects to the 'rarest of rare' doctrine (Bachan Singh v. State of Punjab), POCSO Act, capital punishment jurisprudence, and child rights protection—key GS Paper 2 topics.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Court: Madras High Court", "Ruling: Upheld death penalty in child sexual abuse case", "Observation: Crime termed 'more heinous than murder'", "Relevant laws: POCSO Act, 2012; IPC provisions; 'Rarest of rare' doctrine (Bachan Singh case, 1980)"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Agnikul Cosmos (India) Partners with Finland's ICEYE to Build and Launch Satellites from India", "category": "scitech", "category_name": "Science & Technology", "summary": "Chennai-based space startup Agnikul Cosmos has signed an agreement with Finnish satellite company ICEYE to jointly build and launch satellites from India. ICEYE specialises in Synthetic Aperture Radar (SAR) satellites used for Earth observation. This partnership is significant for India's private space ecosystem and supports the government's push for commercial space activities under IN-SPACe. It also signals growing international confidence in India as a satellite launch hub.", "exam_angle": "Relevant to India's private space sector (IN-SPACe framework), ISRO's commercialisation push, and the Space Policy 2023. Agnikul is known for developing India's first semi-cryogenic rocket (Agnibaan SOrTeD).", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Partnership: Agnikul Cosmos (India) + ICEYE (Finland)", "Purpose: Build and launch SAR (Synthetic Aperture Radar) satellites from India", "Agnikul Cosmos: Private space startup, headquartered in Chennai", "Regulatory framework: IN-SPACe (Indian National Space Promotion and Authorisation Centre)"], "source": "India Today", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Japan Announces $6 Billion AI Investment Plan; Targets 10 Million AI Robots by 2040", "category": "scitech", "category_name": "Science & Technology", "summary": "Japan announced a $6 billion investment plan in Artificial Intelligence, with an ambitious target of deploying 10 million AI-powered robots by 2040. This is part of Japan's national strategy to address demographic challenges (ageing population, labour shortage) through automation and AI. The announcement came during Japanese PM Sanae Takaichi's visit to India, signalling Japan's intent to lead in the global AI race.", "exam_angle": "Relevant to global AI governance, India-Japan tech cooperation (context of PM's visit), and comparative technology policy. Also relevant to GS Paper 3 topics on emerging technologies and their socio-economic implications.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Japan's AI investment plan: $6 billion", "Target: 10 million AI robots deployed by 2040", "Strategic context: Address Japan's ageing population and labour shortages", "Announced during Japanese PM Sanae Takaichi's India visit"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "June 2026 Among Driest on Record in India; Southwest Monsoon Significantly Deficient", "category": "environment", "category_name": "Environment & Ecology", "summary": "June 2026 has been recorded as one of the driest months in recent history across large parts of India, with the southwest monsoon failing to arrive on schedule or deliver normal rainfall. The deficient monsoon has raised concerns about kharif crop sowing, water reservoir levels, and potential drought conditions in several states. The India Meteorological Department (IMD) is being closely watched for updated forecasts. The event is linked to broader climate variability patterns.", "exam_angle": "Monsoon performance is critical for GS Paper 1 (Geography) and GS Paper 3 (Agriculture, Disaster Management). Connects to El Niño/La Niña influence, kharif agriculture, and water security concerns.", "gs_paper": "GS Paper 1 (Geography)", "key_facts": ["June 2026: Among driest on record in India", "Southwest monsoon: Significantly deficient/delayed in June 2026", "Implications: Impact on kharif sowing, water reservoirs, potential drought", "Monitoring agency: India Meteorological Department (IMD)"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Spain Records Over 1,000 Heat-Related Deaths in June 2026 Amid European Heatwave", "category": "environment", "category_name": "Environment & Ecology", "summary": "Spain recorded over 1,000 heat-related deaths in June 2026 as an intense heatwave gripped Europe, with temperatures crossing historic highs. The European heatwave has drawn global attention to the unequal media and policy coverage of extreme heat events compared to similar occurrences in South Asia. Climate scientists have linked the increasing frequency and intensity of heatwaves to anthropogenic climate change. The event has renewed calls for stronger climate adaptation measures.", "exam_angle": "Relevant to GS Paper 3 (Environment, Climate Change, Disaster Management). Connects to IPCC findings on extreme heat events, the 'loss and damage' debate, and the issue of climate justice discussed in COPs.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Country affected: Spain (and broader Europe)", "Heat-related deaths in Spain: Over 1,000 in June 2026", "Cause: Intense European heatwave linked to climate change", "Policy relevance: Highlights need for climate adaptation and heat action plans"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Veteran Theatre and Film Director Vijaya Mehta Passes Away at 91", "category": "culture", "category_name": "Art & Culture", "summary": "Veteran Marathi and Hindi theatre and film director Vijaya Mehta passed away at the age of 91. She was a pioneering figure in Indian theatre, known for her work with the Rangayan theatre group in Mumbai in the 1960s, which was instrumental in introducing experimental and avant-garde theatre to India. She was also a noted film and television director and recipient of several prestigious awards including the Sangeet Natak Akademi Award.", "exam_angle": "Relevant to 'Persons in News' and Indian art and culture (theatre). Questions on Indian theatre movements, Sangeet Natak Akademi, and contributions to performing arts appear in GS Paper 1.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["Vijaya Mehta: Veteran Marathi/Hindi theatre and film director", "Passed away at age: 91", "Known for: Rangayan theatre group, Mumbai (1960s); experimental theatre in India", "Awards: Sangeet Natak Akademi Award (among others)"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "UP SIT Probing Ram Temple Donation Theft Gets 15-Day Extension; Lawyers Boycott Accused", "category": "polity", "category_name": "Polity & Governance", "summary": "A Special Investigation Team (SIT) constituted by the Uttar Pradesh government to probe the alleged theft of donations at the Ayodhya Ram Temple has been granted a 15-day extension by courts. The case has triggered a political controversy, with the Congress party terming it a 'maha paap' and questioning the Prime Minister's silence. Separately, lawyers in Ayodhya boycotted the accused individuals, sparking a debate on the morality vs. legality of such professional boycotts.", "exam_angle": "Relevant to GS Paper 2 topics on governance, accountability of religious trusts, and the role of SITs in high-profile investigations. The lawyers' boycott raises questions about Bar Council ethics and fundamental rights of the accused (Article 22).", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Probe body: SIT constituted by UP government", "Case: Alleged theft of donations at Shri Ram Janmabhoomi Temple, Ayodhya", "Development: SIT granted 15-day extension", "Controversy: Lawyers' boycott of accused raises morality vs. legal right to representation debate"], "source": "The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "US-Iran Indirect Nuclear Talks to Resume in Doha with Mediators", "category": "ir", "category_name": "International Relations", "summary": "The United States and Iran are set to hold indirect talks in Doha, Qatar, mediated by diplomats, to discuss Iran's nuclear programme. The talks come amid ongoing tensions following the collapse of the 2015 JCPOA (Joint Comprehensive Plan of Action). India has historically maintained diplomatic ties with both the US and Iran, and any developments in the Iran nuclear deal have implications for India's energy imports and the Chabahar port project.", "exam_angle": "US-Iran relations and the Iran nuclear deal are standard GS Paper 2 IR topics. India's stakes include Chabahar port (Iran), energy imports, and strategic interests in Central Asia and West Asia.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Format: Indirect talks (with mediators) between US and Iran", "Venue: Doha, Qatar", "Issue: Iran's nuclear programme (context of JCPOA breakdown)", "India's stake: Chabahar port project, energy imports from Iran, West Asia connectivity"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Bangladesh Media Directed Not to Report Sheikh Hasina's Remarks After NDTV Interview", "category": "ir", "category_name": "International Relations", "summary": "Bangladeshi media organisations were reportedly directed by authorities not to publish or broadcast remarks made by former Prime Minister Sheikh Hasina in an interview given to NDTV. Hasina, who is currently in exile in India following her ouster in August 2024, remains a politically sensitive figure in Bangladesh. The move has raised concerns about press freedom in Bangladesh and has diplomatic implications for India-Bangladesh relations.", "exam_angle": "Connects to India-Bangladesh bilateral relations, India's neighbourhood-first policy, and press freedom issues. Sheikh Hasina's political status and India's position are recurring themes in GS Paper 2 IR.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Bangladeshi media directed not to report Sheikh Hasina's NDTV interview remarks", "Sheikh Hasina: Former Bangladesh PM, in exile in India since August 2024", "Raises concerns about press freedom and India-Bangladesh diplomatic sensitivities", "Context: Bangladesh under Muhammad Yunus-led interim government"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "General Dhiraj Seth Takes Charge as 30th Chief of Army Staff", "category": "defence", "category_name": "Defence & Security", "summary": "General Dhiraj Seth assumed charge as the new Chief of Army Staff on June 30, 2026, succeeding General Upendra Dwivedi. The handover ceremony marked a transition in India's top military leadership. Outgoing Chief General Dwivedi noted that future wars will be more integrated and theatre-oriented in nature, signalling the direction of India's military modernisation.", "exam_angle": "Appointments to constitutional/statutory posts and senior military leadership are frequently tested in UPSC Prelims. The shift to theatre commands is a key defence reform topic for GS Paper 3.", "gs_paper": "GS Paper 3 (Defence)", "key_facts": ["New Army Chief: General Dhiraj Seth", "Outgoing Army Chief: General Upendra Dwivedi", "Effective date: June 30, 2026", "Outgoing chief's key remark: Future wars to be integrated and theatre-oriented"], "source": "The Hindu", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "India Semiconductor Mission 2.0 Gets Rs 1.25 Lakh Crore Clearance from Finance Ministry Panel", "category": "scitech", "category_name": "Science & Technology", "summary": "A Finance Ministry panel cleared a Rs 1.25 lakh crore (approximately Rs 1.25 trillion) outlay for India Semiconductor Mission 2.0, paving the way for India to deepen its semiconductor manufacturing ecosystem. The clearance signals a major policy push to reduce import dependence and position India as a global chip manufacturing hub. The original India Semiconductor Mission was launched in 2021 with a Rs 76,000 crore incentive package.", "exam_angle": "Semiconductor self-reliance is a core GS Paper 3 theme linking industrial policy, technology sovereignty, and import substitution. The scale of outlay and its approval body are key facts for Prelims.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Scheme: India Semiconductor Mission 2.0", "Approved outlay: Rs 1.25 lakh crore", "Cleared by: Finance Ministry panel", "Objective: Advance India's semiconductor fabrication and chip design ecosystem"], "source": "NDTV Profit", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Delhi EV Policy 2026 Cleared: Focus on Two-Wheelers and Legacy Vehicle Transition", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "Delhi's Electric Vehicle Policy 2026 (EV Policy 2.0) has been officially cleared, with a significant emphasis on incentivising two-wheelers and managing the transition of legacy internal combustion engine two-wheelers and repair shops. The policy bets big on the two-wheeler segment as the primary driver of EV adoption given its dominance in Delhi's vehicle mix. It also addresses the impact on existing repair shop ecosystems during the EV transition.", "exam_angle": "State EV policies linked to national EV targets (FAME scheme, Net Zero commitments) are relevant for GS Paper 3 (Environment and Economy). Delhi's policy is particularly significant given the city's air quality challenges.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Policy: Delhi EV Policy 2026 (EV Policy 2.0)", "Key focus: Two-wheeler EV adoption and legacy vehicle transition", "Cleared by: Delhi government", "Context: Delhi's severe air pollution and national EV adoption targets"], "source": "The Indian Express", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Pakistan Threatens India Over Indus Waters Treaty as Tensions Escalate", "category": "ir", "category_name": "International Relations", "summary": "A Pakistani minister issued a strong warning to India over the Indus Waters Treaty (IWT), amid ongoing tensions following India's suspension of the treaty after the Pahalgam terror attack in April 2025. Pakistan's Indus Commissioner stated he had written to his Indian counterpart four times over fluctuations in Chenab river flows. India had placed the IWT in abeyance citing cross-border terrorism, marking one of the most significant disruptions to the 1960 treaty.", "exam_angle": "The Indus Waters Treaty (brokered by World Bank in 1960) is a perennial GS Paper 2 (IR) and GS Paper 3 topic. India's suspension and Pakistan's response connect to concepts of treaty obligations, transboundary water disputes, and diplomatic signalling.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Treaty: Indus Waters Treaty, signed 1960, brokered by World Bank", "India suspended/placed IWT in abeyance post-Pahalgam attack (April 2025)", "Rivers in dispute: Chenab (western river allocated to Pakistan)", "Pakistan's Indus Commissioner wrote 4 times to Indian counterpart over Chenab fluctuations"], "source": "Moneycontrol.com", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "US-India Trade Deal in Final Steps: US Ambassador Sergio Gor", "category": "ir", "category_name": "International Relations", "summary": "US Ambassador to India Sergio Gor stated that the bilateral trade deal between the United States and India is in its final stages, with only about 1% of negotiations remaining. Indian-American Congressman Ro Khanna simultaneously warned that the US-India relationship is at its lowest point in 30 years due to Trump administration policies. The trade deal, if concluded, would be a landmark in bilateral economic ties between the world's largest democracies.", "exam_angle": "Bilateral trade negotiations, tariff structures, and US-India economic relations are key GS Paper 2 (IR) topics. The contrast between diplomatic optimism and congressional criticism reflects the complexity of the relationship.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["US Ambassador to India: Sergio Gor", "Status: ~1% of trade deal negotiations remaining", "Ro Khanna (Indian-American Democrat): US-India ties at lowest in 30 years", "Context: Trump-era tariff disputes and bilateral trade deficit tensions"], "source": "The Hindu", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "US-Iran Nuclear Talks: Qatar Confirms No Direct Negotiations in Doha; US Envoys Meet Mediators", "category": "ir", "category_name": "International Relations", "summary": "Qatar confirmed that no direct US-Iran talks would take place in Doha, even as US special envoys Steve Witkoff and Jared Kushner met with Qatari mediators. Iranian officials engaged with Qatari intermediaries on issues including frozen funds. Qatar continues to play a key mediating role in West Asia diplomacy involving the US, Iran, and ongoing Gaza-related negotiations.", "exam_angle": "Iran nuclear diplomacy and Qatar's role as a regional mediator are important for GS Paper 2 (IR) and current geopolitical awareness. The involvement of US envoys and indirect talks format is exam-relevant.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["No direct US-Iran talks in Doha confirmed by Qatar", "US envoys: Steve Witkoff and Jared Kushner", "Qatar's role: Key intermediary/mediator in US-Iran and West Asia diplomacy", "Issues on table: Frozen Iranian funds, nuclear programme"], "source": "The Hindu", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Kotak Mahindra Bank to Acquire Deutsche Bank's India Retail and Wealth Business for Rs 282 Crore", "category": "economy", "category_name": "Economy & Banking", "summary": "Kotak Mahindra Bank announced the acquisition of Deutsche Bank's India retail banking and wealth management business for approximately Rs 282 crore (about $30 million). The deal marks Deutsche Bank's exit from the Indian retail banking segment while strengthening Kotak's retail and wealth management portfolio. The acquisition is subject to regulatory approvals.", "exam_angle": "Banking sector consolidation, foreign bank exits, and RBI's role in approving bank acquisitions are relevant GS Paper 3 (Economy) themes. Kotak Mahindra Bank is a systemically important private bank in India.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Acquirer: Kotak Mahindra Bank", "Seller: Deutsche Bank (India retail and wealth business)", "Deal value: Rs 282 crore (~$30 million)", "Significance: Deutsche Bank exits Indian retail banking segment"], "source": "Reuters", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Government Extends Import Duty Exemption on Key Petrochemical Products Till July 15", "category": "economy", "category_name": "Economy & Banking", "summary": "The Indian government extended the import duty exemption on key petrochemical products until July 15, 2026. The extension is aimed at maintaining domestic supply chain stability and keeping input costs for downstream industries in check. Petrochemicals are critical feedstocks for plastics, fertilisers, and a range of manufacturing sectors.", "exam_angle": "Import duty exemptions, trade policy, and their impact on domestic industries are GS Paper 3 topics. This connects to topics of industrial policy, custom duties, and the role of the Finance Ministry in tariff management.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Measure: Extension of import duty exemption on key petrochemical products", "Extended till: July 15, 2026", "Objective: Stabilise domestic supply chains and manage input costs", "Ministry involved: Finance Ministry (customs/tariff policy)"], "source": "Business Standard", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Finance Ministry's June Review Warns Water Scarcity May Top India's Risk Buffer List", "category": "environment", "category_name": "Environment & Ecology", "summary": "The Finance Ministry's June 2026 monthly economic review issued a new warning that water scarcity may soon top India's risk buffer list, surpassing traditional macroeconomic concerns. The report highlights the growing threat of water stress to agricultural productivity, industrial output, and overall economic resilience. This is a significant policy signal linking environmental sustainability to fiscal and economic planning.", "exam_angle": "Water scarcity as an economic and fiscal risk connects GS Paper 1 (Geography/Environment) with GS Paper 3 (Economy). Finance Ministry economic reviews are primary sources for UPSC current affairs.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Source: Finance Ministry June 2026 monthly economic review", "Warning: Water scarcity may top India's risk buffer list", "Implication: Threat to agriculture, industry, and economic resilience", "Significance: First time FinMin formally flags water as top macro risk"], "source": "Moneycontrol.com", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Europe Heatwave 2026: Record Temperatures in Slovakia and Czechia; Roads Melt", "category": "environment", "category_name": "Environment & Ecology", "summary": "A severe heatwave swept across Eastern Europe in late June 2026, with Slovakia and Czechia recording record-breaking temperatures. The World Meteorological Organization (WMO) noted the unprecedented scale of the heat event, with reports of roads melting and tram tracks buckling in affected cities. The heatwave is consistent with the broader global trend of increasing frequency and intensity of extreme heat events driven by climate change.", "exam_angle": "Extreme weather events linked to climate change, the role of the WMO, and global warming impacts are important for GS Paper 3 (Environment) and GS Paper 1 (Geography). Such events reinforce the science behind IPCC findings.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Affected region: Eastern Europe (Slovakia, Czechia worst affected)", "Authority flagging event: World Meteorological Organization (WMO)", "Impact: Record temperatures, road damage, infrastructure stress", "Context: Part of global trend of intensifying extreme heat events due to climate change"], "source": "NDTV", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Ethanol Blending Programme: Government Tells Supreme Court E20 is an Experiment, Results Expected Next Year", "category": "polity", "category_name": "Polity & Governance", "summary": "The Indian government informed the Supreme Court that the Ethanol Blending Programme (EBP), specifically the E20 target (20% ethanol blending in petrol), is being treated as an experiment and that results will be available by next year. The submission came amid concerns raised before the court about the environmental and engine-related impact of E20 fuel. India has been progressively scaling up ethanol blending as part of its energy transition and agricultural support strategy.", "exam_angle": "The Ethanol Blending Programme connects GS Paper 3 topics of energy policy, agriculture (sugarcane/maize use), environment, and judicial oversight of government schemes. Supreme Court's engagement with executive policy is also a GS Paper 2 theme.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Programme: Ethanol Blending Programme (EBP) — E20 target (20% ethanol in petrol)", "Government position before SC: E20 is an experiment; results expected in one year", "National target: 20% ethanol blending by 2025 (revised timelines under discussion)", "Significance: Connects to energy security, farmers' income, and net-zero commitments"], "source": "India Today", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "HDFC Bank Appoints Former CEC Rajiv Kumar as Chairman", "category": "persons", "category_name": "Persons & Awards in News", "summary": "HDFC Bank, India's largest private sector bank, appointed former Chief Election Commissioner (CEC) Rajiv Kumar as its new Chairman. Rajiv Kumar served as the 24th Chief Election Commissioner of India before retiring. His appointment to a top corporate board is notable given his background in civil services and election administration.", "exam_angle": "Appointments to boards of systemically important banks and the careers of former constitutional functionaries (such as the CEC) are relevant for GS Paper 2 (Polity) and Persons in News for Prelims.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Appointee: Rajiv Kumar (former Chief Election Commissioner of India)", "New role: Chairman, HDFC Bank", "HDFC Bank: India's largest private sector bank", "Rajiv Kumar was the 24th Chief Election Commissioner of India"], "source": "The Indian Express", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Amarnath Yatra 2026: Army Deploys Anti-Drone Arsenal, Radars and Anti-Aircraft Guns for Pilgrim Security", "category": "defence", "category_name": "Defence & Security", "summary": "The Indian Army deployed a multi-layered security grid for the Amarnath Yatra 2026, including anti-drone systems, surveillance radars, and anti-aircraft guns along the pilgrimage route in Jammu & Kashmir. The J&K Lieutenant Governor performed the 'Pratham Puja' to ceremonially mark the commencement of the Yatra. The security deployment reflects heightened vigilance in the region following recent cross-border tensions.", "exam_angle": "Security arrangements for sensitive pilgrimage routes, the role of the Army in internal security, and drone threat mitigation are GS Paper 3 (Internal Security) topics. The Amarnath Yatra is also a Places in News item.", "gs_paper": "GS Paper 3 (Defence)", "key_facts": ["Event: Amarnath Yatra 2026 commencement", "Security deployed: Anti-drone systems, surveillance radars, anti-aircraft guns", "Ceremonial start: 'Pratham Puja' performed by J&K Lieutenant Governor", "Location: Jammu & Kashmir"], "source": "The Times of India", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "National Statistics Day 2026: NSO Celebrates 20th Edition in Mumbai", "category": "reports", "category_name": "Reports & Indices", "summary": "The National Statistics Office (NSO) celebrated the 20th National Statistics Day on June 29, 2026, in Mumbai. National Statistics Day is observed annually on June 29, the birth anniversary of Prof. P.C. Mahalanobis, the father of Indian statistics and founder of the Indian Statistical Institute. The day aims to promote the use of statistics in policymaking and public administration.", "exam_angle": "National Statistics Day, the NSO, and Prof. P.C. Mahalanobis are standard GS Paper 3 (Economy/Data) and Persons in News topics. The NSO is the primary government body for economic data collection and GDP estimation.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Event: 20th National Statistics Day, June 29, 2026", "Organised by: National Statistics Office (NSO)", "Day observed on: June 29 — birth anniversary of Prof. P.C. Mahalanobis", "Prof. Mahalanobis: Founder of Indian Statistical Institute (ISI), Kolkata; architect of India's statistical system"], "source": "PIB", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "RBI's New Funding Rules Impact Indian Proprietary Trading Firms", "category": "economy", "category_name": "Economy & Banking", "summary": "New funding rules issued by the Reserve Bank of India (RBI) have delivered a significant blow to Indian proprietary trading firms by restricting certain funding avenues used for leveraged trading operations. The regulations are aimed at tightening financial sector risk management and reducing systemic vulnerabilities associated with leveraged positions in capital markets. Industry stakeholders have described the impact as a 'body blow' to the prop-trading ecosystem.", "exam_angle": "RBI's regulatory role over capital markets participants, leverage restrictions, and financial sector risk management are GS Paper 3 (Economy) topics. RBI's macro-prudential regulations are frequently tested.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Regulator: Reserve Bank of India (RBI)", "Impact: New funding restrictions on proprietary trading firms", "Purpose: Reduce systemic risk from leveraged trading in capital markets", "Affected entities: Indian proprietary (prop) trading firms"], "source": "Business Standard", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "China Seen as Strategic Winner from US Military Involvement in Middle East: Report", "category": "ir", "category_name": "International Relations", "summary": "A report by The Guardian, citing strategic analysis, concluded that China is emerging as a clear geopolitical winner from the United States' military engagement in the Middle East under the Trump administration. US military focus on West Asia has diverted attention from the Indo-Pacific, allowing China to consolidate strategic and economic positions across the region. The findings have implications for India's foreign policy calculus in the Indo-Pacific.", "exam_angle": "The strategic interplay between US Middle East engagement and Indo-Pacific power dynamics is relevant for GS Paper 2 (IR). China's strategic gains amid US preoccupation is a key theme in contemporary international relations.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Finding: China is the primary strategic beneficiary of US military engagement in Middle East", "Context: Trump administration's military operations in West Asia (2026)", "Mechanism: US distraction from Indo-Pacific allows China strategic consolidation", "Implication: Shifts balance of power calculations in Indo-Pacific, relevant to India's strategic posture"], "source": "The Guardian", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "GST Completes 9 Years: Calls for Simplification, Technology Integration in Next Decade", "category": "economy", "category_name": "Economy & Banking", "summary": "As India's Goods and Services Tax (GST) entered its 9th year (implemented July 1, 2017), analysts and policymakers called for the next decade to focus on simplification of the rate structure, building taxpayer trust, and deeper technology integration. GST has transformed India's indirect tax architecture by subsuming over 17 central and state taxes. Key pending reforms include rationalisation of the rate slabs and inclusion of petroleum products under GST.", "exam_angle": "GST is a flagship constitutional amendment (101st CAA, 2016) and a core GS Paper 3 topic. Anniversary milestones, pending reforms, and the GST Council structure are standard exam themes.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["GST implemented: July 1, 2017 (9th anniversary in 2026)", "Constitutional basis: 101st Constitutional Amendment Act, 2016", "GST subsumed: 17+ central and state taxes", "Key pending reforms: Rate rationalisation, inclusion of petroleum products"], "source": "India Today NE", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "PoK Protesters Warn Pakistan Against Engaging India on Terms That Exclude PoK's Status", "category": "ir", "category_name": "International Relations", "summary": "Protesters in Pakistan-occupied Kashmir (PoK) publicly warned the Pakistani government against any diplomatic engagement with India that does not address PoK's political status, asserting that PoK is not legally part of Pakistan. The protests reflect internal dissent within PoK about Islamabad's authority over the region. This comes amid broader India-Pakistan tensions following Operation Sindoor and subsequent ceasefire.", "exam_angle": "PoK's constitutional and legal status, India's claim over the region (as part of Jammu & Kashmir per India's position), and Pakistan's internal political dynamics are important GS Paper 2 (Polity/IR) topics.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Location: Pakistan-occupied Kashmir (PoK)", "Protesters' assertion: PoK is not legally part of Pakistan", "Context: Post-Operation Sindoor India-Pakistan tensions and ceasefire", "India's position: Entire J&K (including PoK) is an integral part of India"], "source": "NDTV", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "West Bengal BJP Government to Introduce Uniform Civil Code Bill in State Assembly", "category": "polity", "category_name": "Polity & Governance", "summary": "The BJP-led West Bengal government announced plans to introduce a Uniform Civil Code (UCC) Bill in the state assembly, likely in August 2026. Opposition leader Suvendu Adhikari announced a high-powered panel to draft the legislation. West Bengal would become a significant state to attempt UCC legislation following Uttarakhand, which enacted the first state-level UCC in 2024. The move has significant constitutional and political implications given the state's demographic composition.", "exam_angle": "UCC is a Directive Principle under Article 44 of the Constitution; its state-level enactment raises questions about legislative competence and federal dynamics. Connects to GS Paper 2 topics on personal law, secularism, and centre-state relations.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Article 44 of DPSP mandates UCC for citizens throughout India", "Uttarakhand was the first state to enact a UCC law (2024)", "West Bengal BJP government announced panel; Bill likely in Assembly in August 2026", "Suvendu Adhikari (Leader of Opposition/BJP) spearheading the initiative"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Kashmir SIA Files 737-Page Chargesheet Against Yasin Malik in 1990 Sarla Bhat Murder Case", "category": "polity", "category_name": "Polity & Governance", "summary": "The State Investigation Agency (SIA) of Jammu & Kashmir filed a 737-page chargesheet naming Yasin Malik, chief of the Jammu Kashmir Liberation Front (JKLF), as the mastermind in the 1990 rape and murder of Kashmiri Pandit nurse Sarla Bhat. Four other JKLF operatives were also named in the chargesheet, filed 36 years after the incident. Yasin Malik is already serving a life sentence in Tihar Jail for terror-funding cases. The case is significant in the context of justice for Kashmiri Pandit victims of the 1990 exodus.", "exam_angle": "Connects to J&K's special status removal (Article 370), SIA's role in terror investigations, and the broader issue of justice for Kashmiri Pandits. Relevant for questions on security agencies and internal security.", "gs_paper": "GS Paper 3 (Internal Security)", "key_facts": ["SIA filed 737-page chargesheet in Sarla Bhat (1990) murder case", "Yasin Malik named as mastermind; JKLF chief currently serving life sentence for terror-funding", "Five accused named including four JKLF operatives", "Case pertains to 1990 Kashmiri Pandit exodus period"], "source": "The Indian Express", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Cabinet Approves Additional Rs 30,000 Crore Investment in National Investment and Infrastructure Fund (NIIF)", "category": "economy", "category_name": "Economy & Banking", "summary": "The Union Cabinet approved an additional investment commitment of Rs 30,000 crore in the National Investment and Infrastructure Fund (NIIF) to accelerate infrastructure investment and catalyse institutional capital into India. NIIF was established in 2015 as India's sovereign wealth fund for infrastructure. The fresh capital infusion is aimed at attracting long-term institutional investors and scaling up investment in critical infrastructure sectors.", "exam_angle": "NIIF is a key instrument for infrastructure financing in India; its structure as a sovereign wealth fund, its three-fund architecture, and its role in bridging the infrastructure financing gap are important for GS Paper 3 (Economy) and Essay papers.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Cabinet approved Rs 30,000 crore additional investment in NIIF", "NIIF established in 2015 as India's quasi-sovereign wealth fund for infrastructure", "NIIF has three funds: Master Fund, Fund of Funds, Strategic Opportunities Fund", "Objective: catalyse institutional capital and accelerate infrastructure investment"], "source": "PIB", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Delhi Cabinet Approves New EV Policy 2026 with Rs 15,000 Crore Budget", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Delhi Cabinet approved a new Electric Vehicle (EV) Policy 2026 with a total budget of Rs 15,000 crore. Key provisions include zero road tax on electric cars, subsidies for electric two-wheelers and autos, a mandate for only electric autos from 2027, and a phase-out of petrol two-wheelers by 2028. Hybrid vehicles will not receive subsidies under the policy. The policy aims to accelerate Delhi's transition to clean urban mobility.", "exam_angle": "Delhi EV Policy 2026 is relevant for questions on urban transport, clean energy transition, state government schemes, and India's EV ecosystem. Connects to broader National Electric Mobility Mission and FAME scheme.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Delhi EV Policy 2026 approved with Rs 15,000 crore budget", "Zero road tax on electric cars; no subsidies for hybrid vehicles", "Only electric autos permitted from 2027; petrol two-wheelers phased out by 2028", "Policy approved by Delhi Cabinet on June 29, 2026"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Centre Lifts Wartime Petrol and Diesel Sale Restrictions from July 1, 2026", "category": "economy", "category_name": "Economy & Banking", "summary": "The Central Government announced the lifting of restrictions on the sale of petrol and diesel effective July 1, 2026, describing them as 'war-time curbs' imposed during a period of heightened security tensions. These restrictions had been put in place to manage fuel supply and prevent hoarding. The removal signals a return to normalcy in fuel retail operations across India.", "exam_angle": "Connects to India's energy security, essential commodities management, and the government's powers under the Essential Commodities Act. Relevant for questions on petroleum sector regulation and economic policy.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Centre lifts petrol/diesel sale restrictions effective July 1, 2026", "Restrictions were described as 'war-time curbs'", "Decision announced by Central Government (Ministry of Petroleum implied)", "Relevant law: Essential Commodities Act for supply-side controls"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India's Delegation to Iran for Ayatollah Khamenei's Funeral: Bihar Governor and MoS External Affairs", "category": "ir", "category_name": "International Relations", "summary": "India sent a high-level delegation to Iran for the funeral of Supreme Leader Ayatollah Ali Khamenei, comprising Bihar Governor Lt Gen Syed Ata Hasnain and Minister of State for External Affairs Pabitra Margherita. This reflects the significance India attaches to its bilateral relationship with Iran, a key partner for energy imports, the Chabahar Port project, and regional connectivity. Khamenei's death marks a major transition in Iranian politics with implications for the West Asia situation.", "exam_angle": "India-Iran relations are crucial for GS Paper 2 (IR): Chabahar Port, International North-South Transport Corridor (INSTC), energy imports, and India's strategic interests in West Asia. Leadership transition in Iran affects regional geopolitics.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's delegation: Bihar Governor Lt Gen Syed Ata Hasnain and MoS External Affairs Pabitra Margherita", "Iran's Supreme Leader Ayatollah Ali Khamenei passed away (June 2026)", "India-Iran ties: Chabahar Port, INSTC, oil imports are key pillars", "Iran is India's third-largest oil supplier historically"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India-Iran Tensions: Majority of India-Bound Ships 'Go Dark' in Strait of Hormuz", "category": "ir", "category_name": "International Relations", "summary": "Amid escalating tensions involving Iran in West Asia, a majority of India-bound cargo and oil ships were reported to have turned off their Automatic Identification System (AIS) transponders—'going dark'—while transiting the Strait of Hormuz. This is a response to the threat of Iranian interdiction. Approximately 80% of India's crude oil imports pass through the Strait of Hormuz, making disruptions a major concern for India's energy security.", "exam_angle": "The Strait of Hormuz is a critical global oil chokepoint. This event directly tests India's energy security vulnerability and connects to maritime security, freedom of navigation, and West Asia geopolitics in GS Paper 2 and 3.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Strait of Hormuz: ~20% of global oil trade passes through it", "India imports ~80% of its crude oil; majority via Strait of Hormuz", "Ships 'going dark' means turning off AIS transponders to avoid targeting", "Tensions related to US-Iran conflict and Khamenei succession"], "source": "NDTV", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "US-Iran Nuclear Talks: Disagreement Over Next Round of Negotiations in Qatar", "category": "ir", "category_name": "International Relations", "summary": "US President Trump claimed Iran had requested a fresh round of nuclear talks to be held in Qatar on Tuesday, but Iranian officials denied any such meeting was scheduled, saying no technical meeting was expected in the coming days. The contradictory statements come amid active military confrontations between US and Iran-backed forces. This follows a fragile ceasefire agreement and has significant implications for global oil prices and West Asian stability.", "exam_angle": "US-Iran nuclear negotiations, the JCPOA framework, and regional security in West Asia are standard GS Paper 2 IR topics. India as a stakeholder (oil imports, diaspora, Chabahar) makes this directly relevant.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Trump claimed Iran requested talks in Qatar; Iran denied scheduled meeting", "Context: US-Iran military clashes in West Asia (June 2026)", "Doha (Qatar) proposed as venue for nuclear talks", "JCPOA (2015 Iran nuclear deal) remains the framework reference"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Pakistan's Double-Tap Airstrikes on Afghanistan Border Kill 35, Including Children", "category": "ir", "category_name": "International Relations", "summary": "Pakistan carried out 'double-tap' airstrikes on Afghanistan's border region, killing at least 35 people including children. 'Double-tap' strikes involve a second strike shortly after the first to target first responders. The strikes escalated tensions between Pakistan and Afghanistan, with Kabul condemning the attacks. India slammed Pakistan over 'baseless' counter-claims regarding a Karachi attack, reflecting heightened India-Pakistan tensions in the broader context.", "exam_angle": "Pakistan-Afghanistan relations, cross-border terrorism, and regional security dynamics in South Asia are key GS Paper 2 IR topics. Double-tap strikes are considered a violation of international humanitarian law.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Pakistan carried out 'double-tap' airstrikes on Afghanistan border areas", "Death toll: at least 35 including children", "India denied Pakistan's 'baseless' claims regarding a Karachi attack", "Double-tap strikes: second strike targeting first responders, considered potential war crime"], "source": "NDTV", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "US Supreme Court Blocks Trump's Bid to Fire Federal Reserve Governor; Separate Ruling Expands Presidential Powers", "category": "ir", "category_name": "International Relations", "summary": "The US Supreme Court issued two significant rulings: it blocked President Trump's attempt to fire Federal Reserve Governor Lisa Cook, upholding the central bank's independence; in a separate major ruling, the court 'supercharged' Trump's executive powers by expanding presidential authority. The Federal Reserve independence ruling is particularly relevant given ongoing concerns about political interference in monetary policy. These rulings have implications for global financial markets and governance.", "exam_angle": "Federal Reserve independence is a key concept in monetary policy. The US Supreme Court's role in checking executive overreach connects to separation of powers doctrine—a comparative constitutional law topic in GS Paper 2.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["US Supreme Court blocked Trump from firing Federal Reserve Governor Lisa Cook", "Separate ruling 'supercharged' presidential powers in executive authority case", "Federal Reserve: US central bank, founded 1913, sets monetary policy independently", "Central bank independence is a principle adopted by RBI and most major central banks"], "source": "Hindustan Times", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "CBSE Relaxes Three-Language Policy for Classes 7-9; Allows Two Foreign Language Options", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "CBSE relaxed its three-language policy for Classes 7, 8, and 9, allowing students to opt for two foreign languages instead of being required to study a regional language as the third language. CBSE also exempted the current Class 10 batch from the three-language policy. The move drew opposition from Karnataka's state school body, which argued Kannada cannot be replaced as the third language. The policy aligns with the National Education Policy (NEP) 2020 framework but its implementation remains contested.", "exam_angle": "The three-language formula originated with the 1968 National Education Policy and is a key feature of NEP 2020. Questions on language policy, Centre-State jurisdiction over education (Concurrent List), and NEP 2020 are frequent in GS Paper 2.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["CBSE relaxed three-language policy for Classes 7, 8, 9", "Current Class 10 batch exempted from three-language policy", "Students may now opt for two foreign languages instead of mandatory regional language", "Three-language formula: part of NEP 2020; education is on the Concurrent List (Seventh Schedule)"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India Seeks EU Relief on Scrap Metal Export Curbs Threatening India-EU Trade Pact Gains", "category": "ir", "category_name": "International Relations", "summary": "India sought relief from the European Union on restrictions on scrap metal exports, arguing that the curbs threaten to undermine gains from the ongoing India-EU Free Trade Agreement (FTA) negotiations. The EU's Carbon Border Adjustment Mechanism (CBAM) and export restrictions on raw materials are key points of contention. India's steel and manufacturing sectors depend significantly on scrap imports. The issue is being negotiated as part of the broader India-EU trade pact discussions.", "exam_angle": "India-EU FTA, CBAM (Carbon Border Adjustment Mechanism), and trade in raw materials are relevant for GS Paper 2 (IR) and GS Paper 3 (Economy). CBAM is also an environment-trade interface issue.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India seeking EU relief on scrap metal export restrictions", "EU's Carbon Border Adjustment Mechanism (CBAM) is a key trade concern for India", "Issue arises in context of India-EU Free Trade Agreement negotiations", "India-EU FTA talks resumed in 2022 after a decade-long pause"], "source": "Reuters", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India and Maldives Begin Week-Long Free Trade Agreement Negotiations", "category": "ir", "category_name": "International Relations", "summary": "India and the Maldives commenced a week-long round of negotiations for a bilateral Free Trade Agreement (FTA). The talks reflect India's effort to strengthen economic ties with its Indian Ocean neighbour under the 'Neighbourhood First' policy. India is the Maldives' largest trading partner and a key provider of essential commodities, tourism services, and development assistance. The FTA negotiations gain significance against the backdrop of Maldives' recent engagement with China.", "exam_angle": "India-Maldives FTA connects to India's 'Neighbourhood First' policy, SAARC, BIMSTEC, and Indian Ocean regional strategy. Relevant for GS Paper 2 (IR) questions on bilateral relations and island nations.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India-Maldives FTA negotiations commenced (week-long round, June 2026)", "India is Maldives' largest trading partner and key development partner", "Context: India's 'Neighbourhood First' policy; Maldives' China engagement under Muizzu government", "Maldives is strategically located in the Indian Ocean: key for India's maritime security"], "source": "Firstpost", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Orissa High Court Rules Written Grounds of Arrest are Mandatory", "category": "polity", "category_name": "Polity & Governance", "summary": "The Orissa High Court ruled that providing written grounds of arrest to the arrested person is mandatory and not merely a procedural formality. The judgment reinforces the Supreme Court's earlier ruling in Pankaj Bansal v. Union of India (2023) which held that the Enforcement Directorate must supply written arrest grounds. The ruling upholds the fundamental right against arbitrary arrest under Article 22 of the Constitution.", "exam_angle": "Article 22 (Protection against arbitrary arrest) is a core fundamental right topic in GS Paper 2. The ruling connects to landmark SC judgments on arrest procedure and individual liberty.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Orissa High Court: written grounds of arrest are mandatory", "Article 22(1): arrested person must be informed of grounds of arrest", "SC precedent: Pankaj Bansal v. Union of India (2023) on PMLA arrest procedure", "Ruling reinforces protection of personal liberty under Articles 21 and 22"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "HDFC Bank Names Former Finance Secretary Rajiv Kumar as Part-Time Chairman", "category": "persons", "category_name": "Persons & Awards in News", "summary": "HDFC Bank, India's largest private sector bank by assets, appointed former Finance Secretary Rajiv Kumar as its part-time (non-executive) Chairman. Rajiv Kumar had previously served as Finance Secretary in the Ministry of Finance and was also the 25th Chief Election Commissioner of India (2022-2023). The appointment requires RBI approval as per the Banking Regulation Act. This follows the retirement of Atanu Chakraborty as part-time chairman.", "exam_angle": "Appointments to chairmanship of major banks require RBI approval under Section 10B of the Banking Regulation Act 1949. Rajiv Kumar's prior role as CEC is noteworthy for persons-in-news questions.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Rajiv Kumar appointed Part-Time Chairman of HDFC Bank", "Previously served as Finance Secretary (MoF) and 25th Chief Election Commissioner (2022-2023)", "HDFC Bank: India's largest private sector bank", "Bank chairman appointment requires RBI approval under Banking Regulation Act 1949"], "source": "Reuters", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India Women's Cricket Team Qualifies for 2028 Los Angeles Olympics via T20 World Cup Pathway", "category": "persons", "category_name": "Persons & Awards in News", "summary": "The Indian women's cricket team secured qualification for the 2028 Los Angeles Olympics through the T20 World Cup pathway, despite being eliminated from the current T20 World Cup by Australia. Cricket will make its Olympic debut at the LA 2028 Games. India qualified as an automatic qualifier based on ICC rankings/World Cup performance criteria. The men's team's Olympic fate is to be decided by December 2026.", "exam_angle": "Cricket's inclusion in the 2028 LA Olympics is a landmark development. Qualification criteria and the ICC-IOC agreement are relevant for questions on sports governance and India's Olympic performance.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["India women's cricket team qualifies for 2028 LA Olympics", "Cricket returns to Olympics for first time since 1900 at LA 2028", "India qualified via T20 World Cup pathway (ICC qualification system)", "Men's team Olympic qualification to be decided by December 2026"], "source": "India Today", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Harshavardhan GB Becomes India's 97th Chess Grandmaster", "category": "persons", "category_name": "Persons & Awards in News", "summary": "Harshavardhan GB achieved the title of Grandmaster in chess, becoming India's 97th Grandmaster. India has emerged as a global chess powerhouse, with the number of GMs growing rapidly. This comes in the golden era of Indian chess, with Praggnanandhaa, Gukesh (current World Champion), Arjun Erigaisi, and Vidit Gujrathi among the elite. India's chess ecosystem, supported by AICF and private academies, has propelled this growth.", "exam_angle": "India's chess dominance — including D. Gukesh becoming World Chess Champion in 2024 — is a recurring persons-in-news and sports achievement topic in current affairs.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["Harshavardhan GB became India's 97th Chess Grandmaster", "India is the country with the most Grandmasters after Russia", "D. Gukesh is the current World Chess Champion (2024)", "FIDE GM title requires: 2500+ Elo rating and 3 GM norms"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Office of Principal Scientific Adviser Launches TRL Compass Platform; Signs MoU with DSCI", "category": "scitech", "category_name": "Science & Technology", "summary": "The Office of the Principal Scientific Adviser (PSA) to the Government of India launched the Technology Readiness Level (TRL) Compass Platform and signed a Memorandum of Understanding with the Data Security Council of India (DSCI). The TRL Compass is designed to assess and map the technology maturity of Indian innovations and startups. DSCI is an industry body set up by NASSCOM focused on data protection and cybersecurity. The initiative aims to bridge the gap between research and commercialisation.", "exam_angle": "TRL (Technology Readiness Levels, a NASA-originated scale) and the role of the PSA in India's innovation ecosystem are relevant for GS Paper 3 (Sci-Tech). DSCI and data security connect to cybersecurity governance.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["TRL Compass Platform launched by Office of Principal Scientific Adviser (PSA)", "MoU signed between PSA's office and Data Security Council of India (DSCI)", "TRL: Technology Readiness Level scale (1–9) measures maturity of technology", "DSCI: Industry body established by NASSCOM for data protection and cybersecurity"], "source": "PIB", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "European Heatwave June 2026 Breaks Records in Four Countries; Climate Attribution Shows 3.5°C Warming Effect", "category": "environment", "category_name": "Environment & Ecology", "summary": "The June 2026 European heatwave broke temperature records in four countries. Climate scientists using attribution analysis determined that a comparable heatwave in 1976 would have been 3.5°C cooler, demonstrating the direct fingerprint of anthropogenic climate change. The heatwave comes amid a broader pattern of record-breaking global temperatures in 2024–2026. Climate attribution science is now a well-established field connecting individual extreme weather events to climate change.", "exam_angle": "Climate attribution science, the link between global warming and extreme weather events, and international climate commitments (Paris Agreement 1.5°C target) are standard GS Paper 3 (Environment) topics.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["June 2026 European heatwave broke records in four countries", "Climate attribution: heatwave would be 3.5°C cooler in pre-industrial climate (1976 baseline)", "Paris Agreement target: limit warming to 1.5°C above pre-industrial levels", "World Weather Attribution (WWA) is the leading body for extreme weather attribution studies"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Apple Accuses India's CCI of 'Copy-Pasting' Rivals' Claims in Antitrust Investigation", "category": "economy", "category_name": "Economy & Banking", "summary": "Apple Inc. accused India's Competition Commission of India (CCI) of 'copy-pasting' claims made by rivals in its ongoing antitrust investigation against the company. Apple alleged procedural unfairness in how the CCI framed its charges, claiming the investigation improperly relied on competitor submissions. The CCI investigation concerns Apple's App Store policies and the mandatory use of its in-app payment system, similar to cases in the EU and South Korea. The case is significant for India's digital market regulation.", "exam_angle": "CCI's role in regulating digital markets and Big Tech is an important GS Paper 3 (Economy) topic. The Competition Amendment Act 2023 strengthened CCI's powers, including in digital markets.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Apple accused CCI of 'copy-pasting' rival claims in antitrust probe", "CCI investigating Apple's App Store policies and mandatory in-app payment system", "CCI established under Competition Act 2002; strengthened by Competition Amendment Act 2023", "Similar Big Tech antitrust cases ongoing in EU (Digital Markets Act) and South Korea"], "source": "Reuters", "day": "2026-06-29", "day_label": "29 Jun"}], "categories": [{"id": "polity", "name": "Polity & Governance"}, {"id": "economy", "name": "Economy & Banking"}, {"id": "ir", "name": "International Relations"}, {"id": "environment", "name": "Environment & Ecology"}, {"id": "scitech", "name": "Science & Technology"}, {"id": "schemes", "name": "Govt Schemes & Policies"}, {"id": "defence", "name": "Defence & Security"}, {"id": "reports", "name": "Reports & Indices"}, {"id": "persons", "name": "Persons & Awards in News"}, {"id": "culture", "name": "Art & Culture"}]};